let serviceMinutes=0, extraMinutes=0;
let state=loadInitialState();

function today(){const d=new Date();d.setMinutes(d.getMinutes()-d.getTimezoneOffset());return d.toISOString().slice(0,10)}
function serviceYearStart(){const d=new Date();const y=d.getMonth()>=8?d.getFullYear():d.getFullYear()-1;return `${y}-09-01`}
function fmt(m){m=Number(m)||0;return `${Math.floor(m/60)}:${String(Math.abs(m%60)).padStart(2,'0')}`}
function uid(){return crypto.randomUUID?crypto.randomUUID():'id-'+Date.now()+'-'+Math.random().toString(16).slice(2)}
function esc(s=''){return String(s).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
function minFromOld(r){return Number(r.serviceMinutes ?? r.minutes ?? 0)||0}
function extraFromOld(r){return Number(r.extraMinutes ?? (r.extra? r.minutes:0) ?? 0)||0}
function blankState(){return {records:[],contacts:[],favorites:Object.fromEntries(MASTER.filter(x=>x.favorite).map(x=>[x.id,true])),recent:[],baseline:{start:'2025-09-01',serviceMinutes:403*60+5,extraMinutes:0,studies:0,note:'9月〜アプリ開始前'}}}
function normalizeState(raw){const st=Object.assign(blankState(),raw||{});st.records=(st.records||[]).map(r=>({id:r.id||uid(),date:(r.date||today()).replaceAll('/','-'),activityType:r.activityType||'戸別',serviceMinutes:minFromOld(r),extraMinutes:extraFromOld(r),territory:r.territory||'',block:r.block||'',contactId:r.contactId||'',contactName:r.contactName||'',building:r.building||'',address:r.address||'',lat:r.lat??null,lng:r.lng??null,gender:r.gender||'',ageGroup:r.ageGroup||'',rvStatus:r.rvStatus||'関心あり',nextDate:(r.nextDate||'').replaceAll('/','-'),lessonStatus:r.lessonStatus||'未開始',lessonInfo:r.lessonInfo||'',topics:Array.isArray(r.topics)?r.topics:[],publications:r.publications||{},videos:r.videos||{},memo:r.memo||''}));st.contacts=(st.contacts||[]).map(c=>({id:c.id||uid(),name:c.name||c.contactName||'',building:c.building||'',address:c.address||'',lat:c.lat??null,lng:c.lng??null,territory:c.territory||'',block:c.block||'',gender:c.gender||'',ageGroup:c.ageGroup||'',rvStatus:c.rvStatus||'関心あり',nextDate:(c.nextDate||'').replaceAll('/','-'),lessonStatus:c.lessonStatus||'未開始',lessonInfo:c.lessonInfo||'',topics:Array.isArray(c.topics)?c.topics:[],memo:c.memo||'',createdAt:c.createdAt||today(),updatedAt:c.updatedAt||today()}));deriveContacts(st);st.baseline=Object.assign(blankState().baseline,st.baseline||{});st.favorites=st.favorites||{};st.recent=st.recent||[];return st}
function deriveContacts(st){const keyMap=new Map(st.contacts.map(c=>[contactKey(c.name,c.address,c.building),c]));st.records.forEach(r=>{if(!(r.contactName||r.address||r.building))return;let key=contactKey(r.contactName,r.address,r.building);let c=keyMap.get(key);if(!c){c={id:r.contactId||uid(),name:r.contactName||'',building:r.building||'',address:r.address||'',lat:r.lat,lng:r.lng,territory:r.territory||'',block:r.block||'',gender:r.gender||'',ageGroup:r.ageGroup||'',rvStatus:r.rvStatus||'関心あり',nextDate:r.nextDate||'',lessonStatus:r.lessonStatus||'未開始',lessonInfo:r.lessonInfo||'',topics:r.topics||[],memo:'',createdAt:r.date,updatedAt:r.date};st.contacts.push(c);keyMap.set(key,c)}r.contactId=c.id;});}
function contactKey(n,a,b){return [n||'',a||'',b||''].join('|').trim()}
function loadInitialState(){let raw={};for(const k of ['ministryHubV15','ministryHubV3','serviceApp']){try{const t=localStorage.getItem(k);if(t){raw=JSON.parse(t);break}}catch{}}return normalizeState(raw)}
function persist(localOnly=false){localStorage.setItem('ministryHubV15',JSON.stringify(state));localStorage.setItem('ministryHubV3',JSON.stringify(state));if(!localOnly && cloudUser&&cloudDb) cloudSaveDebounced();}
let saveTimer=null;function cloudSaveDebounced(){clearTimeout(saveTimer);saveTimer=setTimeout(()=>saveCloud(false),900)}
function currentMonth(){return today().slice(0,7)}
function inServiceYear(r){return (r.date||'') >= (state.baseline.start||serviceYearStart())}
function calc(){const ym=currentMonth();let ms=0,me=0,ys=Number(state.baseline.serviceMinutes)||0,ye=Number(state.baseline.extraMinutes)||0;state.records.forEach(r=>{if((r.date||'').slice(0,7)===ym){ms+=Number(r.serviceMinutes)||0;me+=Number(r.extraMinutes)||0}if(inServiceYear(r)){ys+=Number(r.serviceMinutes)||0;ye+=Number(r.extraMinutes)||0}});return {ms,me,ys,ye}}
function renderStats(){const c=calc();$('#statMonthService').textContent=fmt(c.ms);$('#statMonthExtra').textContent=fmt(c.me);$('#statMonthTotal').textContent=fmt(c.ms+c.me);$('#statYearService').textContent=fmt(c.ys);$('#statYearExtra').textContent=fmt(c.ye);$('#statYearTotal').textContent=fmt(c.ys+c.ye);$('#statContacts').textContent=state.contacts.length}
function setTimes(){ $('#serviceTime').textContent=fmt(serviceMinutes); $('#extraTime').textContent=fmt(extraMinutes)}
function setTodayIfBlank(){if(!$('#date').value) $('#date').value=today()}
function fillContactSelect(){const sel=$('#contactSelect');const val=sel.value;sel.innerHTML='<option value="">新規・選択なし</option>'+state.contacts.map(c=>`<option value="${c.id}">${esc(c.name||'(名前なし)')} ${esc(c.building||'')} ${esc(c.address||'')}</option>`).join('');sel.value=val}
function renderTopics(selected=[]){$('#topicChecks').innerHTML=topics.map(t=>`<label class="chip"><input type="checkbox" value="${esc(t)}" ${selected.includes(t)?'checked':''}>${esc(t)}</label>`).join('')}
function formData(){const selectedTopics=$$('#topicChecks input:checked').map(i=>i.value);return {date:$('#date').value||today(),activityType:$('#activityType').value,serviceMinutes,extraMinutes,territory:$('#territory').value.trim().padStart($('#territory').value.trim()?3:0,'0'),block:$('#block').value,contactId:$('#contactSelect').value,contactName:$('#contactName').value.trim(),building:$('#building').value.trim(),address:$('#address').value.trim(),lat:window.currentLat??null,lng:window.currentLng??null,gender:$('#gender').value,ageGroup:$('#ageGroup').value,rvStatus:$('#rvStatus').value,nextDate:$('#nextDate').value,lessonStatus:$('#lessonStatus').value,lessonInfo:$('#lessonInfo').value.trim(),topics:selectedTopics,memo:$('#memo').value.trim(),publications:{},videos:{}}}
function upsertContactFromRecord(r){if(!(r.contactName||r.address||r.building))return '';let c=r.contactId?state.contacts.find(x=>x.id===r.contactId):null;if(!c)c=state.contacts.find(x=>contactKey(x.name,x.address,x.building)===contactKey(r.contactName,r.address,r.building));if(!c){c={id:uid(),createdAt:r.date};state.contacts.push(c)}Object.assign(c,{name:r.contactName,building:r.building,address:r.address,lat:r.lat,lng:r.lng,territory:r.territory,block:r.block,gender:r.gender,ageGroup:r.ageGroup,rvStatus:r.rvStatus,nextDate:r.nextDate,lessonStatus:r.lessonStatus,lessonInfo:r.lessonInfo,topics:r.topics,memo:c.memo||'',updatedAt:today()});return c.id}
function saveRecord(){const r=formData();r.contactId=upsertContactFromRecord(r);if(editId){const i=state.records.findIndex(x=>x.id===editId);if(i>=0) state.records[i]=Object.assign(state.records[i],r)}else{r.id=uid();state.records.push(r)}editId=null;persist();clearForm();renderAll();alert('保存しました')}
function clearForm(){editId=null;$('#date').value=today();$('#activityType').value='戸別';$('#territory').value='';$('#block').value='';$('#contactSelect').value='';serviceMinutes=0;extraMinutes=0;setTimes();['contactName','building','address','nextDate','lessonInfo','memo'].forEach(id=>$('#'+id).value='');$('#gender').value='';$('#ageGroup').value='';$('#rvStatus').value='関心あり';$('#lessonStatus').value='未開始';window.currentLat=null;window.currentLng=null;renderTopics([])}
function editRecord(id){const r=state.records.find(x=>x.id===id);if(!r)return;editId=id;showTab('record');$('#date').value=r.date;$('#activityType').value=r.activityType;$('#territory').value=r.territory;$('#block').value=r.block;fillContactSelect();$('#contactSelect').value=r.contactId||'';serviceMinutes=Number(r.serviceMinutes)||0;extraMinutes=Number(r.extraMinutes)||0;setTimes();$('#contactName').value=r.contactName||'';$('#building').value=r.building||'';$('#address').value=r.address||'';window.currentLat=r.lat;window.currentLng=r.lng;$('#gender').value=r.gender||'';$('#ageGroup').value=r.ageGroup||'';$('#rvStatus').value=r.rvStatus||'関心あり';$('#nextDate').value=r.nextDate||'';$('#lessonStatus').value=r.lessonStatus||'未開始';$('#lessonInfo').value=r.lessonInfo||'';$('#memo').value=r.memo||'';renderTopics(r.topics||[])}
function deleteRecord(id){if(confirm('削除しますか？')){state.records=state.records.filter(r=>r.id!==id);persist();renderAll()}}
function renderHistory(){const q=($('#historySearch')?.value||'').toLowerCase();const rows=[...state.records].sort((a,b)=>(b.date||'').localeCompare(a.date||''));$('#historyList').innerHTML=rows.filter(r=>JSON.stringify(r).toLowerCase().includes(q)).map(r=>`<div class="itemrow"><div><b>${esc(r.date)}</b>　${esc(r.activityType)}　通常 ${fmt(r.serviceMinutes)}　付加 ${fmt(r.extraMinutes)}<br><small>${esc([r.territory&&(r.territory+'-'+r.block),r.contactName,r.building,r.address].filter(Boolean).join(' / '))}</small></div><div><button onclick="editRecord('${r.id}')">編集</button><button onclick="deleteRecord('${r.id}')">削除</button></div></div>`).join('')||'<p>記録はまだありません。</p>'}
function renderContacts(){const q=($('#contactSearch')?.value||'').toLowerCase();$('#contactList').innerHTML=state.contacts.filter(c=>JSON.stringify(c).toLowerCase().includes(q)).map(c=>{const visits=state.records.filter(r=>r.contactId===c.id).length;return `<div class="itemrow"><div><b>${esc(c.name||'(名前なし)')}</b> ${esc(c.gender||'')} ${esc(c.ageGroup||'')} <small>${esc(c.rvStatus||'')}</small><br><small>${esc([c.territory&&(c.territory+'-'+c.block),c.building,c.address].filter(Boolean).join(' / '))}</small><br><small>訪問 ${visits}回 / ${esc(c.lessonStatus||'')} ${esc(c.lessonInfo||'')}</small></div><div><button onclick="selectContactForRecord('${c.id}')">記録へ</button><button onclick="focusContactMap('${c.id}')">地図</button></div></div>`}).join('')||'<p>再訪問先はまだありません。</p>'}
function selectContactForRecord(id){showTab('record');$('#contactSelect').value=id;applyContact(id)}
function applyContact(id){const c=state.contacts.find(x=>x.id===id);if(!c)return;$('#contactName').value=c.name||'';$('#building').value=c.building||'';$('#address').value=c.address||'';window.currentLat=c.lat;window.currentLng=c.lng;$('#territory').value=c.territory||'';$('#block').value=c.block||'';$('#gender').value=c.gender||'';$('#ageGroup').value=c.ageGroup||'';$('#rvStatus').value=c.rvStatus||'関心あり';$('#nextDate').value=c.nextDate||'';$('#lessonStatus').value=c.lessonStatus||'未開始';$('#lessonInfo').value=c.lessonInfo||'';renderTopics(c.topics||[])}
function renderLibrary(filter='favorite'){let arr=MASTER.filter(x=>filter==='all'||(filter==='favorite'?state.favorites[x.id]:x.kind===filter));$('#libraryGrid').innerHTML=arr.map(it=>`<div class="card"><div class="thumb">${it.image?`<img src="${it.image}">`:''}</div><b>${esc(it.title)}</b><br><small>${esc(it.category)}</small><br><button onclick="toggleFav('${it.id}')">${state.favorites[it.id]?'★':'☆'}</button></div>`).join('')}
function toggleFav(id){state.favorites[id]=!state.favorites[id];persist();renderLibrary()}
async function geocodeAddress(addr){if(!addr)throw new Error('住所が空です');const url='https://nominatim.openstreetmap.org/search?format=json&limit=1&q='+encodeURIComponent(addr);const res=await fetch(url,{headers:{'Accept':'application/json'}});const data=await res.json();if(!data[0])throw new Error('住所から位置を見つけられませんでした');return {lat:+data[0].lat,lng:+data[0].lon,display:data[0].display_name}}
async function pinFromAddress(){try{const pos=await geocodeAddress($('#address').value);window.currentLat=pos.lat;window.currentLng=pos.lng;alert('ピンを作成しました')}catch(e){alert(e.message)}}
function openGoogleMap(){const q=$('#address').value || [window.currentLat,window.currentLng].filter(Boolean).join(',');if(q) window.open('https://www.google.com/maps/search/?api=1&query='+encodeURIComponent(q),'_blank')}
function currentLocation(){if(!navigator.geolocation){alert('現在地を取得できません');return}navigator.geolocation.getCurrentPosition(async p=>{window.currentLat=p.coords.latitude;window.currentLng=p.coords.longitude;$('#address').value=`${window.currentLat},${window.currentLng}`;alert('現在地を入れました')},e=>alert(e.message),{enableHighAccuracy:true,timeout:10000})}
function renderMap(){if(!$('#mapCanvas'))return;if(!map){map=L.map('mapCanvas').setView([34.71,137.73],12);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'© OpenStreetMap'}).addTo(map)}map.eachLayer(l=>{if(l instanceof L.Marker)map.removeLayer(l)});let pts=state.contacts.filter(c=>c.lat&&c.lng);pts.forEach(c=>L.marker([c.lat,c.lng]).addTo(map).bindPopup(`<b>${esc(c.name||'(名前なし)')}</b><br>${esc(c.address||'')}<br>${esc(c.rvStatus||'')}`));if(pts[0])map.setView([pts[0].lat,pts[0].lng],13);setTimeout(()=>map.invalidateSize(),100)}
function focusContactMap(id){showTab('map');setTimeout(()=>{const c=state.contacts.find(x=>x.id===id);if(c?.lat&&c?.lng){map.setView([c.lat,c.lng],16)}},100)}
function renderSummary(){const by={};state.records.forEach(r=>{by[r.activityType]??={s:0,e:0};by[r.activityType].s+=Number(r.serviceMinutes)||0;by[r.activityType].e+=Number(r.extraMinutes)||0});$('#summaryBox').innerHTML=Object.entries(by).map(([k,v])=>`<div class="itemrow"><b>${esc(k)}</b><span>通常 ${fmt(v.s)} / 付加 ${fmt(v.e)}</span></div>`).join('')||'<p>記録がありません。</p>'}
function renderBaseline(){if($('#baseStart')){$('#baseStart').value=state.baseline.start||serviceYearStart();$('#baseService').value=state.baseline.serviceMinutes||0;$('#baseExtra').value=state.baseline.extraMinutes||0;$('#baseStudies').value=state.baseline.studies||0}}
function saveBaseline(){state.baseline.start=$('#baseStart').value||serviceYearStart();state.baseline.serviceMinutes=Number($('#baseService').value)||0;state.baseline.extraMinutes=Number($('#baseExtra').value)||0;state.baseline.studies=Number($('#baseStudies').value)||0;persist();renderAll();alert('保存しました')}
function mergeState(a,b){a=normalizeState(a);b=normalizeState(b);const records=new Map();[...a.records,...b.records].forEach(r=>{if(r?.id)records.set(r.id,r)});const contacts=new Map();[...a.contacts,...b.contacts].forEach(c=>{if(c?.id)contacts.set(c.id,c)});return normalizeState({...a,...b,records:[...records.values()],contacts:[...contacts.values()],favorites:{...a.favorites,...b.favorites},recent:[...(a.recent||[]),...(b.recent||[])].filter((v,i,arr)=>v&&arr.indexOf(v)===i).slice(0,50),baseline:(sumBase(b.baseline)>=sumBase(a.baseline)?b.baseline:a.baseline)})}
function sumBase(x){return (Number(x?.serviceMinutes)||0)+(Number(x?.extraMinutes)||0)}
function firebaseConfigTextToObject(txt){txt=(txt||'').trim();if(!txt)throw new Error('Firebase設定が空です');txt=txt.replace(/^const\s+firebaseConfig\s*=\s*/,'').replace(/;\s*$/,'');try{return JSON.parse(txt)}catch{return Function('return ('+txt+')')()}}
function getCfg(){try{return JSON.parse(localStorage.getItem(FIREBASE_CONFIG_KEY)||'null')||DEFAULT_FIREBASE_CONFIG}catch{return DEFAULT_FIREBASE_CONFIG}}
function setSyncStatus(t){$('#syncStatus').textContent=t}
function initFirebase(config){if(!window.firebase){setSyncStatus('Firebaseライブラリを読めません');return}try{if(!firebase.apps.length)firebase.initializeApp(config);cloudAuth=firebase.auth();cloudDb=firebase.firestore();cloudAuth.onAuthStateChanged(async u=>{cloudUser=u;$('#googleLoginBtn').hidden=!!u;$('#googleLogoutBtn').hidden=!u;if(!u){setSyncStatus('未ログイン');return}setSyncStatus('同期済み：'+(u.email||u.displayName));await pullCloud(false);});}catch(e){setSyncStatus('Firebase設定エラー：'+e.message)}}
function cloudRef(){return cloudDb.collection('users').doc(cloudUser.uid).collection('apps').doc('ministryHub')}
async function pullCloud(show=true){if(!cloudUser||!cloudDb)return;const snap=await cloudRef().get();if(snap.exists&&snap.data()?.state){remoteKnown=snap.data().state;state=mergeState(state,remoteKnown);persist(true);renderAll();if(show)alert('クラウドと統合しました')}else if(show)alert('クラウドにデータはまだありません')}
async function saveCloud(show=true){if(!cloudUser||!cloudDb){alert('ログインしてください');return}if(state.records.length===0 && remoteKnown?.records?.length){alert('空データで上書きしないため保存を止めました。先にクラウドから取得してください。');return}await cloudRef().set({state,updatedAt:firebase.firestore.FieldValue.serverTimestamp(),version:APP_VERSION});setSyncStatus('同期済み：'+(cloudUser.email||cloudUser.displayName));if(show)alert('クラウドへ保存しました')}
function renderAll(){fillContactSelect();renderStats();renderHistory();renderContacts();renderLibrary();renderSummary();renderBaseline();if($('#tab-map').classList.contains('active'))renderMap()}
function showTab(name){$$('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===name));$$('.panel').forEach(p=>p.classList.remove('active'));$('#tab-'+name).classList.add('active');if(name==='map')setTimeout(renderMap,50)}
function exportJson(){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='service-record-backup.json';a.click()}
function exportCsv(){const head=['日付','区分','通常分','付加分','区域','ブロック','名前','性別','年代','住所','ステータス','次回','レッスン','メモ'];const rows=state.records.map(r=>[r.date,r.activityType,r.serviceMinutes,r.extraMinutes,r.territory,r.block,r.contactName,r.gender,r.ageGroup,r.address,r.rvStatus,r.nextDate,r.lessonInfo,r.memo].map(v=>'"'+String(v??'').replaceAll('"','""')+'"').join(','));const blob=new Blob(['\ufeff'+head.join(',')+'\n'+rows.join('\n')],{type:'text/csv'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='service-record.csv';a.click()}
async function importJson(e){const f=e.target.files?.[0];if(!f)return;try{const obj=JSON.parse(await f.text());state=mergeState(state,obj);persist();renderAll();alert('復元しました')}catch(err){alert('復元に失敗：'+err.message)}e.target.value=''}
function init(){if(navigator.serviceWorker) navigator.serviceWorker.getRegistrations().then(rs=>rs.forEach(r=>r.unregister()));$('#date').value=today();renderTopics([]);setTimes();$$('.tabs button').forEach(b=>b.onclick=()=>showTab(b.dataset.tab));$$('.timebox button').forEach(b=>b.onclick=()=>{const t=b.dataset.target;const v=Number(b.dataset.min)||0;if(t==='serviceMinutes')serviceMinutes=Math.max(0,serviceMinutes+v);else extraMinutes=Math.max(0,extraMinutes+v);setTimes()});$('#saveRecordBtn').onclick=saveRecord;$('#clearBtn').onclick=clearForm;$('#contactSelect').onchange=e=>applyContact(e.target.value);$('#geoBtn').onclick=currentLocation;$('#addressPinBtn').onclick=pinFromAddress;$('#mapOpenBtn').onclick=openGoogleMap;$('#historySearch').oninput=renderHistory;$('#contactSearch').oninput=renderContacts;$('#saveBaselineBtn').onclick=saveBaseline;$('#exportBtn').onclick=exportJson;$('#exportCsvBtn').onclick=exportCsv;$('#importBtn').onclick=()=>$('#importFile').click();$('#importFile').onchange=importJson;$$('[data-lib]').forEach(b=>b.onclick=()=>renderLibrary(b.dataset.lib));$('#firebaseConfigInput').value=JSON.stringify(getCfg(),null,2);$('#saveFirebaseConfigBtn').onclick=()=>{try{const cfg=firebaseConfigTextToObject($('#firebaseConfigInput').value);localStorage.setItem(FIREBASE_CONFIG_KEY,JSON.stringify(cfg));alert('Firebase設定を保存しました');location.reload()}catch(e){alert(e.message)}};$('#googleLoginBtn').onclick=()=>cloudAuth.signInWithPopup(new firebase.auth.GoogleAuthProvider()).catch(e=>alert(e.message));$('#googleLogoutBtn').onclick=()=>cloudAuth.signOut();$('#cloudPullBtn').onclick=()=>pullCloud(true);$('#cloudUploadBtn').onclick=()=>saveCloud(true);initFirebase(getCfg());renderAll();}
document.addEventListener('DOMContentLoaded',init);
window.editRecord=editRecord;window.deleteRecord=deleteRecord;window.toggleFav=toggleFav;window.selectContactForRecord=selectContactForRecord;window.focusContactMap=focusContactMap;
